namespace sv_fcdb0ca1a5ae4a0aae8528f2605a3337.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped state container holding the currently selected warehouse.
/// Each Blazor Server circuit gets its own instance, so users are isolated.
/// </summary>
public class WarehouseStateService
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A — East" },
        new() { Id = "WH-B", Name = "Warehouse B — West" },
        new() { Id = "WH-C", Name = "Warehouse C — Central" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public WarehouseInfo CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_fcdb0ca1a5ae4a0aae8528f2605a3337.Services;

/// <summary>
/// Simulates a database query for low-stock inventory items.
/// Scoped per circuit so each user gets independent results.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async database query
        return Task.FromResult(_random.Next(0, 16));
    }
}

@using sv_fcdb0ca1a5ae4a0aae8528f2605a3337.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="form-label mb-0 me-2 text-muted small">Warehouse:</label>
    <select class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChange;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
            await WarehouseState.SetWarehouseAsync(id);
    }

    private async Task HandleStateChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChange;
    }
}

.warehouse-selector {
    display: flex;
    align-items: center;
}

.warehouse-selector select {
    width: auto;
    min-width: 200px;
}

@using sv_fcdb0ca1a5ae4a0aae8528f2605a3337.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="alert-badge-wrapper">
    @if (_lowStockCount.HasValue && _lowStockCount.Value > 0)
    {
        <span class="badge bg-danger rounded-pill">@_lowStockCount</span>
    }
    else if (_lowStockCount.HasValue)
    {
        <span class="badge bg-success rounded-pill">0</span>
    }
</span>

@code {
    private int? _lowStockCount;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChange;
        StartPolling();
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = Task.Run(async () =>
        {
            // Immediate first fetch
            await RefreshCount();

            while (!token.IsCancellationRequested)
            {
                try
                {
                    if (!await _timer.WaitForNextTickAsync(token)) break;
                    await RefreshCount();
                }
                catch (OperationCanceledException) { break; }
            }
        }, token);
    }

    private async Task RefreshCount()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lowStockCount = count;
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleWarehouseChange()
    {
        // Warehouse changed — refresh immediately
        await RefreshCount();
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChange;
        StopPolling();
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_fcdb0ca1a5ae4a0aae8528f2605a3337.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="lead text-muted">
    Managing: <strong>@WarehouseState.CurrentWarehouse.Name</strong>
    <span class="text-secondary">(@WarehouseState.CurrentWarehouseId)</span>
</p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card border-danger mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <span>Low-Stock Alerts</span>
                @if (_isPolling)
                {
                    <span class="spinner-grow spinner-grow-sm text-danger" role="status" title="Live polling active"></span>
                }
            </div>
            <div class="card-body text-center">
                @if (_lowStockCount.HasValue)
                {
                    <h2 class="card-title display-4 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                        @_lowStockCount
                    </h2>
                    <p class="card-text text-muted">items below minimum level</p>
                }
                else
                {
                    <p class="text-muted">Loading…</p>
                }
            </div>
            <div class="card-footer text-muted small">
                Refreshes every 10 seconds &bull; Last checked: @(_lastChecked?.ToString("HH:mm:ss") ?? "—")
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header">Warehouse Info</div>
            <div class="card-body">
                <dl class="mb-0">
                    <dt>Site ID</dt>
                    <dd>@WarehouseState.CurrentWarehouseId</dd>
                    <dt>Name</dt>
                    <dd>@WarehouseState.CurrentWarehouse.Name</dd>
                </dl>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header">Session</div>
            <div class="card-body">
                <p class="small text-muted mb-0">
                    Each manager session is isolated via a scoped Blazor Server circuit.
                    Switching warehouses here does not affect other users.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private DateTime? _lastChecked;
    private bool _isPolling;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChange;
        StartPolling();
    }

    private void StartPolling()
    {
        StopPolling();
        _isPolling = true;
        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = Task.Run(async () =>
        {
            await RefreshCount();

            while (!token.IsCancellationRequested)
            {
                try
                {
                    if (!await _timer.WaitForNextTickAsync(token)) break;
                    await RefreshCount();
                }
                catch (OperationCanceledException) { break; }
            }
        }, token);
    }

    private async Task RefreshCount()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lowStockCount = count;
        _lastChecked = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleWarehouseChange()
    {
        await RefreshCount();
    }

    private void StopPolling()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChange;
        StopPolling();
    }
}

